module serial2parallel (
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0]dout_parallel,
    output reg dout_valid
);

reg [3:0] cnt;
reg valid;
reg [7:0] data;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 4'd0;
        valid <= 1'b0;
        data <= 8'd0;
    end else begin
        case(cnt)
            4'd0: begin
                if(din_valid == 1'b1) begin
                    cnt <= cnt + 4'd1;
                    data[7-cnt] <= din_serial;
                end
            end
            4'd1: begin
                if(din_valid == 1'b1) begin
                    cnt <= cnt + 4'd1;
                    data[7-cnt] <= din_serial;
                end
            end
            4'd2: begin
                if(din_valid == 1'b1) begin
                    cnt <= cnt + 4'd1;
                    data[7-cnt] <= din_serial;
                end
            end
            4'd3: begin
                if(din_valid == 1'b1) begin
                    cnt <= cnt + 4'd1;
                    data[7-cnt] <= din_serial;
                end
            end
            4'd4: begin
                if(din_valid == 1'b1) begin
                    cnt <= cnt + 4'd1;
                    data[7-cnt] <= din_serial;
                end
            end
            4'd5: begin
                if(din_valid == 1'b1) begin
                    cnt <= cnt + 4'd1;
                    data[7-cnt] <= din_serial;
                end
            end
            4'd6: begin
                if(din_valid == 1'b1) begin
                    cnt <= cnt + 4'd1;
                    data[7-cnt] <= din_serial;
                end
            end
            4'd7: begin
                if(din_valid == 1'b1) begin
                    cnt <= cnt + 4'd1;
                    data[7-cnt] <= din_serial;
                end
            end
            default: begin
                cnt <= 4'd0;
                valid <= 1'b1;
            end
        endcase
    end
end

assign dout_parallel = data;
assign dout_valid = valid;
endmodule
